\begin{center}
  \textbf{\large Verifica di Chimica: Introduzione alla Chimica Organica} \\
  \vspace{0.3cm}
  \small \textbf{Nome:} \underline{\hspace{6cm}} \quad \textbf{Classe e Data:} \underline{\hspace{4cm}} \\
  \vspace{0.3cm}
  \textit{\small Svolgere tutti gli esercizi mostrando i passaggi.}
\end{center}
\subsection*{Esercizio 1: Nomenclatura e Struttura}
Considera i seguenti composti organici:
\begin{enumerate}
    \item Disegna la struttura di Lewis dell'etanolo. (15 pt)
    \item Indica il nome IUPAC del composto con formula bruta $C_4H_{10}O$ e struttura
   $CH_3-CH(OH)-CH_2-CH_3$. (15 pt)
    \item Identifica la classe di appartenenza e il gruppo funzionale principale del 2-butanone. (20 pt)
\end{enumerate}

\subsection*{Esercizio 2: Reazioni di Alcheni}

Si consideri il 2-butene.
\begin{enumerate}
    \item Scrivi l'equazione bilanciata della reazione di idrogenazione catalitica del 2-butene. (15 pt)
    \item Indica il prodotto principale della reazione di idratazione acido-catalizzata del 2-butene. Giustifica brevemente la tua risposta applicando la regola di Markovnikov. (20 pt)
    \item Il 2-butene reagisce con il bromo ($Br_2$) in soluzione acquosa. Quale prodotto si forma principalmente e quale regola chimica si applica? (15 pt)
\end{enumerate}

\subsection*{Esercizio 3: Stereoisomeria e Gruppi Funzionali}
Considera la molecola dell'acido 2-cloropropanoico.
\begin{enumerate}
    \item Disegna le strutture di tutti gli stereoisomeri possibili per questa molecola, indicando le configurazioni assolute (R/S). (25 pt)
    \item Quale tipo di isomeria presenta la coppia di composti:
   $CH_3-CH(OH)-COOH$ e $CH_3-CO-CH_2OH$? Motiva la tua risposta. (25 pt)
\end{enumerate}
\end{document}

